module linear_regression (
    input [15:0] x,  // Input value
    input signed [15:0] a,  // Coefficient
    input signed [15:0] b,  // Intercept
    output signed [31:0] y   // Output result
);
      wire _n01 = (a * x)[0] ^ b[0];
  wire _c01 = (a * x)[0] & b[0];
  wire _n02 = (a * x)[1] ^ b[1] ^ _c01;
  wire _c02 = ((a * x)[1] & b[1]) | ((a * x)[1] & _c01) | (b[1] & _c01);
  wire _n03 = (a * x)[2] ^ b[2] ^ _c02;
  wire _c03 = ((a * x)[2] & b[2]) | ((a * x)[2] & _c02) | (b[2] & _c02);
  wire _n04 = (a * x)[3] ^ b[3] ^ _c03;
  wire _c04 = ((a * x)[3] & b[3]) | ((a * x)[3] & _c03) | (b[3] & _c03);
  assign y = {_n01, _n02, _n03, _n04};  // Linear regression formula
endmodule
